from flask import Flask, session, redirect, url_for, request, render_template_string

app = Flask(__name__)
app.secret_key = 'super_secret_key_for_session_management' # Bu anahtarı üretim ortamında güvenli ve rastgele bir değerle değiştirin!

LOGIN_FORM_HTML = """
<!doctype html>
<title>Giriş Yap</title>
<h1>Giriş Yap</h1>
<form method="post" action="/login">
    <label for="username">Kullanıcı Adı:</label><br>
    <input type="text" id="username" name="username"><br>
    <label for="password">Şifre:</label><br>
    <input type="password" id="password" name="password"><br><br>
    <input type="submit" value="Giriş">
</form>
"""

DASHBOARD_HTML = """
<!doctype html>
<title>Panel</title>
<h1>Hoşgeldin, {{ username }}!</h1>
<p>Bu senin kişisel panelin.</p>
<p><a href="/logout">Çıkış Yap</a></p>
<p><a href="/">Anasayfa</a></p>
"""

HOME_PAGE_LOGGED_OUT_HTML = """
<!doctype html>
<title>Anasayfa</title>
<h1>Uygulamaya Hoşgeldin!</h1>
<p>Giriş yapmadınız.</p>
<p><a href="/login">Buradan giriş yapın</a></p>
"""

HOME_PAGE_LOGGED_IN_HTML = """
<!doctype html>
<title>Anasayfa</title>
<h1>Uygulamaya Hoşgeldin!</h1>
<p>Giriş yaptınız: {{ username }}.</p>
<p><a href="/dashboard">Panele Git</a></p>
<p><a href="/logout">Çıkış Yap</a></p>
"""

@app.route('/')
def home():
    if 'username' in session:
        return render_template_string(HOME_PAGE_LOGGED_IN_HTML, username=session['username'])
    return render_template_string(HOME_PAGE_LOGGED_OUT_HTML)

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        # Basit bir kontrol, gerçek uygulamada veritabanı ile doğrulanmalı
        if username == 'kullanici' and password == 'sifre':
            session['username'] = username
            return redirect(url_for('dashboard'))
        else:
            return "Geçersiz kullanıcı adı veya şifre. <a href='/login'>Tekrar dene</a>"
    return render_template_string(LOGIN_FORM_HTML)

@app.route('/dashboard')
def dashboard():
    if 'username' in session:
        return render_template_string(DASHBOARD_HTML, username=session['username'])
    return redirect(url_for('login'))

@app.route('/logout')
def logout():
    session.pop('username', None)
    return redirect(url_for('home'))

if __name__ == '__main__':
    app.run(debug=True)
